import React, { type ReactNode } from 'react';
import { type MenuRef, type MenuProps } from 'antd';
import { type MenuItemType as AntdMenuType, type SubMenuType as AntdSubMenuType } from 'antd/es/menu/interface';
type OldItemType = Extract<MenuProps['items'], any[]>[0];
type OldMenuItemGroupType = Extract<OldItemType, {
    type: 'group';
}>;
export type MenuDividerType = Extract<OldItemType, {
    type: 'divider';
}>;
export interface MenuItemType extends AntdMenuType {
    selectable?: boolean;
    isLoading?: boolean;
}
export interface SubMenuItemType extends Omit<AntdSubMenuType, 'children'> {
    children: ItemType[];
    itemKey?: React.Key;
}
export interface MenuItemGroupType extends Omit<OldMenuItemGroupType, 'children'> {
    children?: ItemType[];
}
export interface MenuItemCustomType extends Pick<MenuItemType, 'key'> {
    type: 'custom';
    component: ReactNode;
    hidden?: boolean;
}
export type ItemType<T extends MenuItemType = MenuItemType> = T | MenuItemGroupType | SubMenuItemType | MenuDividerType | MenuItemCustomType | null;
export interface IMenuProps extends Omit<MenuProps, 'items'> {
    items?: ItemType[];
    ref?: React.Ref<MenuRef>;
    dataTestId?: string;
}
export declare const Menu: React.ForwardRefExoticComponent<Omit<IMenuProps, "ref"> & React.RefAttributes<MenuRef>>;
export {};
